-- Custom championship scoring, per channel config. Replaces the old hardcoded CustomPoints table that
-- only applied to club 146. custom_scoring_enabled gates the custom standings recomputation (was the
-- `clubId == "146"` check); scoring_strategy selects how points are derived; scoring_table is the
-- position->points map for the LOOKUP_TABLE strategy (positions not listed score 1).
ALTER TABLE discord_club_configuration
    ADD COLUMN custom_scoring_enabled BOOLEAN NOT NULL DEFAULT FALSE,
    ADD COLUMN scoring_strategy       VARCHAR(255),
    ADD COLUMN scoring_table          JSONB;

